head.script:
scwin.strCurrDate   = $c.date.getServerDateTime("yyyyMMdd");            // 서버기준 날짜
scwin.strStartDate  = $c.date.addDate(scwin.strCurrDate, -2);           // 시작일자
scwin.strFirstDate  = scwin.strCurrDate.substring(0, 6) + "01";         // 월초
scwin.adptYm        = scwin.strCurrDate;

scwin.onpageload = function() {
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    acb_madeYn.setValue("0"); //미생성
	acb_selpchClsCd.setValue("1");

	ed_rsltsStdDtSt.setValue(scwin.strCurrDate);
	ed_rsltsStdDtEnd.setValue(scwin.strCurrDate);

	$c.gus.cfDisableBtn([cbx_selpchItemCdYn]);
}

scwin.comCodeEnter = function(nameObj, eventFn) {

    nameObj.bind('onkeydown', function(e) {
        if (e.keyCode == 13) {
            eventFn.apply(nameObj);
        }
    });
}



//-------------------------------------------------------------------------
// function name : scwin.f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_validDate = async function() {

    var rsltsStdDtStSub     = ed_rsltsStdDtSt.getValue().substring(0,6);
	var rsltsStdDtEndSub    = ed_rsltsStdDtEnd.getValue().substring(0,6);

    // 날짜 필수 체크
    if(ds_condition.get("rsltsStdDtSt") == "" || ds_condition.get("rsltsStdDtEnd") == ""){
        await $c.win.alert("실적기간은 필수 입력 항목입니다.");
        ed_rsltsStdDtSt.focus();
        return false;
    }  

    // FROM - TO 체크
    if (!$c.gus.cfIsAfterDate(ed_rsltsStdDtSt.getValue(), ed_rsltsStdDtEnd.getValue())) {
        await $c.win.alert(MSG_CM_ERR_039);
        ed_rsltsStdDtSt.focus();
        return false;
    }

    // FROM - TO 동일월 체크
    if(rsltsStdDtStSub != rsltsStdDtEndSub){
		await $c.win.alert("실적기간 조회 기간은  같은 월 이어야 합니다.");	
        ed_rsltsStdDtSt.focus();
		return false;
	}
    return true;

}
scwin.f_Retrieve = async function() {   

	if(acb_madeYn.getValue() == "2"){

        if(ed_selpchItemCd.getValue() == "" || ed_selpchItemNm.getValue() == ""){
			await $c.win.alert("매출입항목은 필수 입력 항목입니다.");
            ed_selpchItemCd.focus();
			return false;
		}	

        if (await scwin.f_validDate() == false) return; 
	} else {
		 if (await scwin.f_validDate() == false) return;
	}

	ds_condition.set("adptYm", ed_rsltsStdDtSt.getValue().substring(0,6));

	if(cbx_selpchItemCdYn.getValue() == '1'){
		ds_condition.set("selpchItemCdYn", 1);
	}else{
		ds_condition.set("selpchItemCdYn", 0);
    }

    $c.sbm.execute(sbm_retrieve);
}


//-------------------------------------------------------------------------
// function name : scwin.f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {     

   	var checkedCnt      = 0;
    var validate        = false;

    for(var i = 0; i < ds_results.getRowCount(); i++){

        var nPos = i + 1;

		if(ds_results.getCellData(i, "chk") == "1" ){

            var rowStatus = ds_results.getRowStatus(i);

            //update
			if( rowStatus == 'U' ) { 

				if (ds_results.getCellData(i, "adptYm") == "") {
					//2023.08.02 적용년월은 조회기간 FROM년월 에서 입력한 실적일자 기준으로 셋팅으로 변경
					ds_results.setCellData(i, "adptYm", ds_results.getCellData(i, "rsltsStdDt").substring(0,6));
				} else {
					if ( ds_results.getCellData(i, "adptYm") != ds_results.getCellData(i, "rsltsStdDt").substring(0,6) ) {
						$c.win.alert(nPos + "행의 실적일자는 " + ds_results.getCellData(i, "adptYm").substring(0,4) + "년" + ds_results.getCellData(i, "adptYm").substring(4,6) + "월 " +"적용년월 기간내여야 합니다.");
						return false;
					}
				}			
				//공제			
				if(ds_results.getCellData(i, "selpchClsCd") == "1"){
					ds_results.setCellData(i, "sellYn", 1);		//매출여부
					ds_results.setCellData(i, "pchsYn", 0);		//매입여부
					ds_results.setCellData(i, "deductYn", 1);	//공제여부				

					ds_results.setCellData(i, "sellClntNo", ds_results.getCellData(i, "clntNo"));	//매출거래처번호 
					ds_results.setCellData(i, "sellAmt", ds_results.getCellData(i, "clntAmt")); 	//매출금액
					ds_results.setCellData(i, "sellVat", ds_results.getCellData(i, "clntVat")); 	//매출부가세

					ds_results.setCellData(i, "pchsClntNo", ""); 	//매입거래처번호
					ds_results.setCellData(i, "pchsAmt", ""); 		//매입금액
					ds_results.setCellData(i, "pchsVat", ""); 		//매입부가세					
				}
				//지급
				else if(ds_results.getCellData(i, "selpchClsCd") == "2"){
					ds_results.setCellData(i, "sellYn", 0);		//매출여부
					ds_results.setCellData(i, "pchsYn", 1);		//매입여부
					ds_results.setCellData(i, "deductYn", 0);	//공제여부	

					ds_results.setCellData(i, "pchsClntNo", ds_results.getCellData(i, "clntNo")); 	//매입거래처번호
					ds_results.setCellData(i, "pchsAmt", ds_results.getCellData(i, "clntAmt")); 	//매입금액
					ds_results.setCellData(i, "pchsVat", ds_results.getCellData(i, "clntVat")); 	//매입부가세

					ds_results.setCellData(i, "sellClntNo", "");	//매출거래처번호 
					ds_results.setCellData(i, "sellAmt", ""); 		//매출금액
					ds_results.setCellData(i, "sellVat", ""); 		//매출부가세					
				}

				if(ds_results.getCellData(i, "homeClntNo") == ""){
					ds_results.setCellData(i, "homeClntNo", ds_results.getCellData(i, "sellClntNo"));
				}

				if(ds_results.getCellData(i, "closeYn") == 1){
					$c.win.alert(nPos + "번째 실적은 마감처리되어 수정,삭제 할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 2){
					$c.win.alert(nPos + "번째 실적은 거래명세서생성 상태여서 수정,삭제 할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 3){
					$c.win.alert(nPos + "번째 실적은 계산서생성 상태여서 수정,삭제 할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 4){
					$c.win.alert(nPos + "번째 실적은 전표확정 상태여서 수정,삭제 할 수 없습니다.");
					return;
				}

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "vehclNo")) ){ 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량번호 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "homeClntNm")) ){ 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["소속거래처 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "clntNm")) ){ 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매니저 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}	

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "rsltsStdDt")) ){ 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["실적일자 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}

                validate = $c.date.isDate(ds_results.getCellData(i, "rsltsStdDt"));
				if(!validate){
					$c.win.alert(nPos + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
					return;
				}				
				checkedCnt++;		
			}		

			//insert
			if(rowStatus == 'C' ){ 
				ds_results.setCellData(i, "chk", "1");

				if (ds_results.getCellData(i, "adptYm") == "") {
					//2023.08.02 적용년월은 조회기간 FROM년월 에서 입력한 실적일자 기준으로 셋팅으로 변경
					ds_results.setCellData(i, "adptYm", ds_results.getCellData(i, "rsltsStdDt").substring(0,6));
				} else {
					if ( ds_results.getCellData(i, "adptYm") != ds_results.getCellData(i, "rsltsStdDt").substring(0,6) ) {
						$c.win.alert(nPos + "행의 실적일자는 " + ds_results.getCellData(i, "adptYm").substring(0,4) + "년" + ds_results.getCellData(i, "adptYm").substring(4,6) + "월 " +"적용년월 기간내여야 합니다.");
						return false;
					}
				}	

				//공제			
				if(ds_results.getCellData(i, "selpchClsCd") == "1"){
					ds_results.setCellData(i, "sellYn", 1);		//매출여부
					ds_results.setCellData(i, "pchsYn", 0);		//매입여부
					ds_results.setCellData(i, "deductYn", 1);	//공제여부				
					ds_results.setCellData(i, "sellClntNo", ds_results.getCellData(i, "clntNo"));	//매출거래처번호 
					ds_results.setCellData(i, "sellAmt", ds_results.getCellData(i, "clntAmt")); 	//매출금액
					ds_results.setCellData(i, "sellVat", ds_results.getCellData(i, "clntVat")); 	//매출부가세
				}
				//지급
				else if(ds_results.getCellData(i, "selpchClsCd") == "2"){
					ds_results.setCellData(i, "sellYn", 0);		//매출여부
					ds_results.setCellData(i, "pchsYn", 1);		//매입여부
					ds_results.setCellData(i, "deductYn", 0);	//공제여부
					ds_results.setCellData(i, "sellClntNo", ""); 		
					ds_results.setCellData(i, "pchsClntNo", ds_results.getCellData(i, "clntNo")); 	//매입거래처번호
					ds_results.setCellData(i, "pchsAmt", ds_results.getCellData(i, "clntAmt")); 	//매입금액
					ds_results.setCellData(i, "pchsVat", ds_results.getCellData(i, "clntVat")); 	//매입부가세
				}				

				if(ds_results.getCellData(i, "homeClntNo") == ""){
					ds_results.setCellData(i, "homeClntNo", ds_results.getCellData(i, "sellClntNo"));
				}

				if(ds_results.getCellData(i, "vehclNo") == ""){
					$c.win.alert(nPos + "행의 차량번호는 필수 입력 항목 입니다.");
					return false;
				}	

				if(ds_results.getCellData(i, "homeClntNm") == ""){
					$c.win.alert(nPos + "행의 소속거래처는 필수 입력 항목 입니다.");
					return false;
				}

				if(ds_results.getCellData(i, "clntNm") == ""){
					$c.win.alert(nPos + "행의 매니저는 필수 입력 항목 입니다.");
					return false;
				}				

				if(ds_results.getCellData(i, "rsltsStdDt") == ""){
					$c.win.alert(nPos + "행의 실적일자는 필수 입력 항목 입니다.");
					return false;
				}	

                validate = $c.date.isDate(ds_results.getCellData(i, "rsltsStdDt"));

				if(!validate){
					$c.win.alert(nPos + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
					return;
				}								
				checkedCnt++;
			}

			//delete
			if(rowStatus == 'D' ){ 

				if(ds_results.getCellData(i, "closeYn") == 1){
					$c.win.alert(nPos + "번째 실적은 마감처리되어 삭제할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 2){
					$c.win.alert(nPos + "번째 실적은 거래명세서생성 상태여서 삭제할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 3){
					$c.win.alert(nPos + "번째 실적은 계산서생성 상태여서 삭제할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 4){
					$c.win.alert(nPos + "번째 실적은 전표확정 상태여서 삭제할 수 없습니다.");
					return;
				}

				checkedCnt++;
			}
		}
	}//for

	if(checkedCnt == 0){
		$c.win.alert("체크된 데이터가 없습니다. 수정하려는 Row의 첫 열의 체크박스를 선택해 주십시오.");
		return false;
	}

    var confirm = await $c.win.confirm(MSG_CM_CRM_001);
   	if (confirm) {
        $c.sbm.execute(sbm_save);
   	}
}


//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {

	ed_clntNoCd.setValue("");				//거래처번호
	ed_clntNoNm.setValue("");				//거래처명

	ed_selpchItemCd.setValue("");		//매출입항목
	ed_selpchItemNm.setValue("");		//매출입항목명

	ed_vehclNoCd.setValue("");
	ed_vehclNoNm.setValue("");

	acb_madeYn.setValue("0"); 		    //미생성
	acb_selpchClsCd.setValue("1");  	//지급

	ed_rsltsStdDtSt.setValue(scwin.strCurrDate);
    ed_rsltsStdDtEnd.setValue(scwin.strCurrDate);
}




//-------------------------------------------------------------------------
// function name : scwin.f_openPopUp
// function desc : popup
//-------------------------------------------------------------------------
scwin.isOpenPopup = false;
scwin.rowPos = -1;
scwin.f_openCommonPopUpSync = function(disGubun, pCode, pName, pClose, pAllSearch) {
    return new Promise(function(resolve, reject) {
        scwin.f_openCommonPopUp(disGubun, pCode, pName, pClose, pAllSearch, resolve);
    });
}

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch, callback) {

    var pWhere  = '';
    scwin.isOpenPopup = true;

	switch (disGubun)
  	{
  		//거래처
  		case 1:
		    pWhere = "";
		    if(cbx_repClntYn.getValue() == '1'){
		    	pWhere = "RP";
		    }

            udc_comCodeCln.setSelectId('retrieveSubsidaryClntList');
            udc_comCodeCln.cfCommonPopUp(
                    scwin.udc_comCodeCln_callback
                    , pCode
                    , pName
                    , pClose
                    , '5'
                    , '거래처'
                    , '150,170'
                    , null
                    , pWhere
                    , null
                    , null
                    , null
                    , null
                    , null
                    , pAllSearch						// 전체검색허용여부	("F")
                    , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
			break;

		//매출입항목	
		case 2:		
            pWhere = ',,,,,';
            udc_comCodeSelpchItem.setSelectId('retrieveSelpchItemInfo');
			udc_comCodeSelpchItem.cfCommonPopUpAsync(
				scwin.udc_comCodeSelpchItem_callback
                , pCode
                , pName
                , pClose
                , '매출입항목'
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , pAllSearch 
                , null							
		  	);									

			break;

		//차량번호	
		case 3:		
            udc_comCodeVehclNo.setSelectId('retrieveSubsidaryVehclList');
			udc_comCodeVehclNo.cfCommonPopUp(
				scwin.udc_comCodeVehclNo_callback
                , pCode
                , pName
                , pClose
                , null
                , '차량번호'
                , null
                , null
                , pWhere
                , '400'
                , null
                , null
                , null
                , null
                , pAllSearch							// 전체검색허용여부	("F")
			    , "차량번호,차량단축코드,차량번호"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")							
		  	);	

			break;

		//그리드차량번호	
		case 4:  
            scwin.udc_comCode_Grid_Vehcl_callback(null);
            udc_comCode_Grid_Vehcl.setSelectId('retrieveSubsidaryVehclList');
            udc_comCode_Grid_Vehcl.cfCommonPopUpAsync(
				  function(ret) {
                    scwin.udc_comCode_Grid_Vehcl_callback(ret, callback)
                  }
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , '400'
                , null
                , null
                , null
                , null
                , pAllSearch							// 전체검색허용여부	("F")
			    , "차량번호,차량단축코드,차량번호"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")						
		  	);	
        	break;	

		//그리드소속거래처	
		case 5:  
            scwin.udc_comCode_Grid_Clnt1_callback(null);
            udc_comCode_Grid_Clnt1.setSelectId('retrieveSubsidaryClntList');
            udc_comCode_Grid_Clnt1.cfCommonPopUpAsync(
                function(ret) {
				  scwin.udc_comCode_Grid_Clnt1_callback(ret, callback)
                }
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , pAllSearch						// 전체검색허용여부	("F")
			    , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")						
		  	);				
			break;	

		//그리드매니저	
		case 6:  
            scwin.udc_comCode_Grid_Clnt2_callback(null);
            udc_comCode_Grid_Clnt2.setSelectId('retrieveSubsidaryClntList');
            udc_comCode_Grid_Clnt2.cfCommonPopUp(
                function(ret) {
				    scwin.udc_comCode_Grid_Clnt2_callback(ret, callback)
                }
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , pAllSearch						// 전체검색허용여부	("F")
			    , "거래처,거래처코드,거래처명"		// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")							
		  	);	
            break;

		//그리드매출입항목
		case 7:
            pWhere = ',,,,,';
            scwin.udc_comCode_Grid_SelpchItem_callback(null);
            udc_comCode_Grid_SelpchItem.setSelectId('retrieveSelpchItemInfo');
			udc_comCode_Grid_SelpchItem.cfCommonPopUp(
                function(ret) {
				    scwin.udc_comCode_Grid_SelpchItem_callback(ret, callback)
                }
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , pWhere
                , null
                , null
                , null
                , null
                , null
                , null 
                , null							
		  	);	
            break;		
		default:
  			break;
  	}

    scwin.isOpenPopup = true;
}

