scwin.f_goDtlAmtPop = async function(row){

    var rowIndex = ds_results.getRowPosition();
    var pURL = "/ui/ja/dn/workrslts/ja_401_01_05p.xml";
    var options = {
        type : 'browserPopup',
        modal : true,
        popupName : '상세금액등록',
        width : 300,
        height : 500
    }
    var data = {
        dtlMgntNo : ds_results.getCellData(rowIndex, 'dtlMgntNo')
    }
    var rtnList = await $c.win.openPopup(pURL, options, data);

    if(rtnList.rowPosition != null && rtnList.totDtlAmt != ""){
        var colIndex = grd_results.getColumnIndex('clntAmt');

        ds_results.setCellData(rowIndex, "clntAmt", rtnList.totDtlAmt);
        ds_results.setCellData(rowIndex, "dtlMgntNo",  rtnList.dtlMgntNo);

        grd_results.setFocusedCell(rowIndex, colIndex);
    }
}

